PRAGMA foreign_keys=OFF;
CREATE TABLE products (
    id TEXT PRIMARY KEY,
    name_en TEXT,
    name_zh TEXT,
    name_vi TEXT,
    name_tl TEXT,
    category_id TEXT,
    description_en TEXT,
    description_zh TEXT,
    description_vi TEXT,
    description_tl TEXT,
    specs TEXT,
    features_en TEXT,
    features_zh TEXT,
    features_vi TEXT,
    features_tl TEXT,
    images TEXT,
    main_image INTEGER DEFAULT 0,
    img TEXT,
    status TEXT DEFAULT 'active',
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
    updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
  );
CREATE TABLE categories (
    id TEXT PRIMARY KEY,
    name_en TEXT,
    name_zh TEXT,
    name_vi TEXT,
    name_tl TEXT
  , description_en TEXT, description_zh TEXT, description_vi TEXT, description_tl TEXT);
CREATE TABLE news (
  id INTEGER PRIMARY KEY,
  date TEXT,
  status TEXT DEFAULT 'draft',
  views INTEGER DEFAULT 0,
  images TEXT,
  category TEXT,
  title_en TEXT,
  title_zh TEXT,
  title_vi TEXT,
  title_tl TEXT,
  slug_en TEXT,
  slug_zh TEXT,
  slug_vi TEXT,
  slug_tl TEXT,
  content_en TEXT,
  content_zh TEXT,
  content_vi TEXT,
  content_tl TEXT,
  seo_title_en TEXT,
  seo_title_zh TEXT,
  seo_title_vi TEXT,
  seo_title_tl TEXT,
  alt_en TEXT,
  alt_zh TEXT,
  alt_vi TEXT,
  alt_tl TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE cases (
  id INTEGER PRIMARY KEY,
  slug TEXT UNIQUE,
  region_en TEXT,
  region_zh TEXT,
  region_vi TEXT,
  region_tl TEXT,
  category_en TEXT,
  category_zh TEXT,
  category_vi TEXT,
  category_tl TEXT,
  date TEXT,
  video TEXT,
  images TEXT,
  client_en TEXT,
  client_zh TEXT,
  client_vi TEXT,
  client_tl TEXT,
  status TEXT DEFAULT 'draft',
  title_en TEXT,
  title_zh TEXT,
  title_vi TEXT,
  title_tl TEXT,
  content_en TEXT,
  content_zh TEXT,
  content_vi TEXT,
  content_tl TEXT,
  outcomes_en TEXT,
  outcomes_zh TEXT,
  outcomes_vi TEXT,
  outcomes_tl TEXT,
  materials_en TEXT,
  materials_zh TEXT,
  materials_vi TEXT,
  materials_tl TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE scenarios (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  image TEXT,
  order_num INTEGER DEFAULT 0,
  is_active INTEGER DEFAULT 1,
  title_en TEXT,
  title_zh TEXT,
  title_vi TEXT,
  title_tl TEXT,
  description_en TEXT,
  description_zh TEXT,
  description_vi TEXT,
  description_tl TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP
, products TEXT DEFAULT '[]');
CREATE TABLE about (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  section TEXT,
  key TEXT,
  value_en TEXT,
  value_zh TEXT,
  value_vi TEXT,
  value_tl TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE contacts (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  name TEXT,
  email TEXT,
  company TEXT,
  product TEXT,
  message TEXT,
  lang TEXT DEFAULT 'en',
  is_read INTEGER DEFAULT 0,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE social_links (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  platform TEXT UNIQUE,
  url TEXT,
  icon TEXT,
  is_active INTEGER DEFAULT 1,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE translations (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  lang TEXT,
  key TEXT,
  value TEXT,
  UNIQUE(lang, key)
);
CREATE TABLE accounts (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  username TEXT UNIQUE,
  password TEXT,
  role TEXT DEFAULT 'editor',
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE team_members (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  slug TEXT UNIQUE,
  visible INTEGER DEFAULT 1,
  order_num INTEGER DEFAULT 0,
  name_en TEXT,
  name_zh TEXT,
  name_vi TEXT,
  name_tl TEXT,
  role_en TEXT,
  role_zh TEXT,
  role_vi TEXT,
  role_tl TEXT,
  desc_en TEXT,
  desc_zh TEXT,
  desc_vi TEXT,
  desc_tl TEXT,
  photo TEXT,
  email TEXT,
  color TEXT,
  initial TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
DELETE FROM sqlite_sequence;
CREATE INDEX idx_news_status ON news(status);
CREATE INDEX idx_cases_status ON cases(status);
CREATE INDEX idx_translations_lang ON translations(lang);
