INSERT INTO products VALUES('one-way-vision','One Way Vision ','单向透视膜','Tầm nhìn một chiều',' Isang Daan na Pananaw','advertising-media','one way vision material is typically applied for indoor and outdoor signage and wide-format digital printing such as vehicle advertising, irregular planes, and outdoor durable signage and product labels, especially for one-way vision window films.','单向透视膜通常应用于室内外标识、大幅面数码打印场景（如车辆广告、不规则平面、户外耐用标识及产品标签），尤其适用于单向透视窗膜。','Vật liệu tầm nhìn một chiều thường được sử dụng cho biển hiệu trong nhà và ngoài trời, in kỹ thuật số khổ lớn như quảng cáo trên xe, bề mặt không đều, biển hiệu bền ngoài trời và nhãn sản phẩm, đặc biệt là phim cửa sổ tầm nhìn một chiều.',replace('Ang materyal na isang daan na pananaw ay karaniwang ginagamit para sa mga karatula sa loob at labas ng bahay at malaking-format na digital printing tulad ng advertising sa sasakyan, hindi regular na mga eroplano, at matibay na mga karatula sa labas at mga label ng produkto, lalo na para sa mga window film na isang daan na pananaw.\n','\n',char(10)),'[{"k_en": "Hole Size", "v_en": "1.6mm / 2.0mm / 3.0mm", "v_tl": "1.6mm / 2.0mm / 3.0mm", "k_zh": "\u5b54\u5c3a\u5bf8", "k_vi": "K\u00edch th\u01b0\u1edbc l\u1ed7", "k_tl": "Hole Size", "v_zh": "1.6mm / 2.0mm / 3.0mm", "v_vi": "1.6mm / 2.0mm / 3.0mm"}, {"k_en": "Film Thickness", "v_en": "140-180 micron", "v_tl": "140-180 micron", "k_zh": "\u819c\u539a\u5ea6", "k_vi": "\u0110\u1ed9 d\u00e0y m\u00e0ng", "k_tl": "Film Thickness", "v_zh": "140-180\u5fae\u7c73", "v_vi": "140 - 180 micron"}, {"k_en": "Transmittance", "v_en": "60% / 65% / 70%", "v_tl": "60% / 65% / 70%", "k_zh": "\u900f\u5c04\u7387", "k_vi": "S\u1ef1 truy\u1ec1n t\u1ea3i", "k_tl": "Transmittance", "v_zh": "60% / 65% / 70%", "v_vi": "60% / 65% / 70%"}, {"k_en": "Size", "v_en": "1.27/1.52/1.8/2.3m \u00d7 50m", "v_tl": "1.27/1.52/1.8/2.3m \u00d7 50m", "k_zh": "\u5927\u5c0f", "k_vi": "K\u00edch th\u01b0\u1edbc", "k_tl": "Size", "v_zh": "1.27/1.52/1.8/2.3m x 50 m", "v_vi": "1.27 / 1.52 / 1.8 / 2.3m \u00d7 50m"}, {"k_en": "Application", "v_en": "Vehicle Windows, Glass Surfaces", "v_tl": "Vehicle Windows, Glass Surfaces", "k_zh": "\u5e94\u7528", "k_vi": "\u1ee8ng d\u1ee5ng:", "k_tl": "Application", "v_zh": "\u8f66\u7a97\u3001\u73bb\u7483\u8868\u9762", "v_vi": "C\u1eeda s\u1ed5 xe, b\u1ec1 m\u1eb7t k\u00ednh"}]','["50/50 perforation ratio for optimal visibility balance", "Vibrant external graphics while maintaining inside view", "Suitable for vehicle windows and glass facades", "UV resistant for long-lasting outdoor performance", "Easy to apply and remove without residue", "Ideal for advertising, privacy, and branding", "777777"]',NULL,NULL,NULL,'["/product-images/1_%E5%AE%A4%E5%86%85%E5%86%99%E7%9C%9F%E6%9D%90%E6%96%99_01_4f7491.jpg"]',0,NULL,'active','2026-05-04 06:18:19','2026-05-04 06:18:19');
