INSERT INTO products VALUES('1775573085772','xiaoxiao','小小','Xiaoxiao','','advertising-media','Lightweight, rigid, and weather-resistant PVC foam board, ideal for indoor/outdoor signage, display stands, and advertising installations. Features excellent printability, easy cutting, and moisture-proof performance, perfect for tropical climates in Vietnam and the Philippines. With a smooth surface and long-lasting durability, it’s a top choice for retail displays, exhibition booths, and OEM wholesale for advertising engineering projects.','轻质、刚性且耐候的PVC泡沫板，非常适合室内外标识、展示架和广告安装。具有优异的打印性、易于裁剪和防潮性能，非常适合越南和菲律宾的热带气候。凭借光滑的表面和持久耐用，它是零售展示、展位和OEM批发的首选，用于广告工程项目。','Tấm xốp PVC nhẹ, cứng và chịu được thời tiết, lý tưởng cho bảng hiệu trong nhà / ngoài trời, giá trưng bày và lắp đặt quảng cáo. Có khả năng in tuyệt vời, dễ cắt và chống ẩm, hoàn hảo cho khí hậu nhiệt đới ở Việt Nam và Philippines. Với bề mặt nhẵn và độ bền lâu dài, đây là sự lựa chọn hàng đầu cho các màn hình bán lẻ, gian hàng triển lãm và bán buôn OEM cho các dự án kỹ thuật quảng cáo.','','[{"k_en": "Item Name", "v_en": "SAV120/140", "v_tl": "SAV120/140", "k_zh": "\u9879\u76ee\u540d\u79f0", "k_vi": "T\u00ean m\u1ee5c", "k_tl": "Item Name", "v_zh": "SAV 120/140", "v_vi": "SAV120 / 140"}, {"k_en": "Release paper", "v_en": "120/140g\u00b15g", "v_tl": "120/140g\u00b15g", "k_zh": "\u79bb\u578b\u7eb8", "k_vi": "Gi\u1ea5y ph\u00e1t h\u00e0nh", "k_tl": "Release paper", "v_zh": "120/140\u514b\u00b1 5\u514b", "v_vi": "120 / 140g \u00b1 5g"}, {"k_en": "Film", "v_en": "80/100micron\u00b15micron", "v_tl": "80/100micron\u00b15micron", "k_zh": "\u819c", "k_vi": "Phim", "k_tl": "Film", "v_zh": "80/100\u5fae\u7c73\u00b1 5\u5fae\u7c73", "v_vi": "80 / 100micron \u00b1 5micron"}, {"k_en": "Surface", "v_en": "Glossy/ Matte", "v_tl": "Glossy/ Matte", "k_zh": "\u8868\u9762", "k_vi": "B\u1ec1 m\u1eb7t", "k_tl": "Surface", "v_zh": "\u5149\u6cfd/\u54d1\u5149", "v_vi": "Glossy / Matte"}, {"k_en": "Glue", "v_en": "Semi removable, 22\u03bcm\u00b12\