INSERT INTO translations VALUES(548,'zh','home.faq.products.q1','你们的主要产品是什么？');
INSERT INTO translations VALUES(549,'zh','home.faq.products.a1','我们专业生产自粘乙烯基、PVC柔性横幅、刻字膜、亚克力板、PVC泡沫板和展示设备。我们也提供定制规格服务。');
INSERT INTO translations VALUES(550,'zh','home.faq.products.q2','你们提供定制尺寸和规格吗？');
INSERT INTO translations VALUES(551,'zh','home.faq.products.a2','是的，我们提供定制尺寸、厚度和规格。请提供您的详细需求，我们的团队将为您量身定制解决方案。');
INSERT INTO translations VALUES(552,'zh','home.faq.products.q3','你们的最小起订量是多少？');
INSERT INTO translations VALUES(553,'zh','home.faq.products.a3','我们的最小起订量因产品类型而异。通常，标准产品的最小起订量为100件。对于定制订单，请直接联系我们了解具体要求。');
INSERT INTO translations VALUES(554,'zh','home.faq.ordering.q1','你们接受哪些付款方式？');
INSERT INTO translations VALUES(555,'zh','home.faq.ordering.a1','我们接受T/T（电汇）、PayPal和西联汇款。对于新客户，我们可能需要30%定金，余额在发货前支付。');
INSERT INTO translations VALUES(556,'zh','home.faq.ordering.q2','处理我的订单需要多长时间？');
INSERT INTO translations VALUES(557,'zh','home.faq.ordering.a2','生产时间因产品而异。标准产品3-7天内发货。定制订单可能需要10-15天。我们将在订单确认后提供预计交付日期。');
INSERT INTO translations VALUES(558,'zh','home.faq.ordering.q3','我可以在下大单之前申请样品吗？');
INSERT INTO translations VALUES(559,'zh','home.faq.ordering.a3','是的，我们为标准产品提供免费样品。客户只需承担运费。对于定制样品，请联系我们获取报价。');
INSERT INTO translations VALUES(560,'zh','home.faq.shipping.q1','你们提供国际运输吗？');
INSERT INTO translations VALUES(561,'zh','home.faq.shipping.a1','是的，我们向全球50多个国家发货。我们与DHL、FedEx、UPS等主要快递公司以及海运合作，为大额订单提供运输服务。');
INSERT INTO translations VALUES(562,'zh','home.faq.shipping.q2','运费是多少？');
INSERT INTO translations VALUES(563,'zh','home.faq.shipping.a2','运费取决于目的地、重量和运输方式。我们提供有竞争力的价格，会在您下单时为您提供准确的运费报价。');
INSERT INTO translations VALUES(564,'zh','home.faq.shipping.q3','交货需要多长时间？');
INSERT INTO translations VALUES(565,'zh','home.faq.shipping.a3','快递（DHL/FedEx/UPS）需要5-7个工作日。海运需要25-35天，具体取决于目的地国家和港口。');
INSERT INTO translations VALUES(566,'zh','home.faq.quality.q1','你们的产品有认证吗？');
INSERT INTO translations VALUES(567,'zh','home.faq.quality.a1','是的，我们已获得ISO 9001:2015认证。我们的产品符合国际质量标准，出口到欧洲、美洲、东南亚和中东市场。');
INSERT INTO translations VALUES(568,'zh','home.faq.quality.q2','你们提供质量保证吗？');
INSERT INTO translations VALUES(569,'zh','home.faq.quality.a2','当然！我们提供100%质量保证。如果您收到缺陷产品，我们将免费更换或提供全额退款。');
INSERT INTO translations VALUES(570,'zh','home.faq.quality.q3','你们能提供测试报告或样品吗？');
INSERT INTO translations VALUES(571,'zh','home.faq.quality.a3','是的，我们可以根据要求提供测试报告、证书和样品。我们的质量控制团队在发货前进行严格检查。');
