INSERT INTO translations VALUES(579,'zh','faq.a1_5',replace('我们提供全系列高性能广告材料，专为东南亚市场量身定制，包括：\nSintra板（PVC泡沫板）\n自粘乙烯基（可打印、彩色、反光）\n光学级防刮晶膜\nPVC柔性横幅\n丙烯板\nLED通道字母材料\n反光片及其他功能性薄膜','\n',char(10)));
INSERT INTO translations VALUES(580,'zh','home.faq.products.q5','你们提供哪些广告材料？');
