INSERT INTO translations VALUES(1055,'tl','home.why.rd.title','In-house na Koponan ng R&D');
INSERT INTO translations VALUES(1056,'tl','home.why.rd.desc','Itinatag noong 2023 ang dedicated na R&D team. Patuloy na product innovation at custom formulation para sa iyong partikular na market requirements.');
