INSERT INTO translations VALUES(1209,'tl','faq.q1_5','Anong mga materyales sa advertising ang iyong inaalok?');
INSERT INTO translations VALUES(1210,'tl','faq.a1_5',replace('Nagbibigay kami ng isang buong hanay ng mga materyales sa advertising na may mataas na pagganap na nababagay para sa mga merkado ng Timog-silangang Asya, kabilang ang:\nSintra board (PVC foam board)\nSelf-adhesive vinyl (nai-print, kulay, sumasalamin)\nOptical grade anti-scratch crystal film\nPVC flex banner\nEmail Address *\nMga materyales sa titik ng LED channel\nMapanimdim na sheeting at iba pang mga functional na pelikula','\n',char(10)));
INSERT INTO translations VALUES(1211,'tl','home.faq.products.q5','Anong mga advertising materials ang inaalok ninyo?');
INSERT INTO translations VALUES(1212,'tl','home.faq.products.a5','Nagbibigay kami ng kumpletong hanay ng mga high-performance advertising materials para sa mga merkado sa Timog-Silangang Asya, kabilang ang: PVC foam board, self-adhesive vinyl, optical grade crystal film, PVC flex banner, acrylic sheet, LED channel letter materials, at reflective sheeting.');
INSERT INTO translations VALUES(1213,'tl','faq.q2_4','Paano ako mag-order?');
INSERT INTO translations VALUES(1214,'tl','faq.a2_4',replace('Maaari kang mag-order sa pamamagitan ng:\n1, Makipag-ugnay sa aming koponan sa pagbebenta nang direkta sa iyong mga kinakailangan sa materyal, dami, at address ng paghahatid\n2 、 Humiling ng isang libreng quote at sample (kung kinakailangan)\n3 、 Kumpirmahin ang order at gumawa ng pagbabayad\n4 、 Inaayos namin ang produksyon at pagpapadala, at nagbibigay ng mga update sa pagsubaybay sa real-time','\n',char(10)));
INSERT INTO translations VALUES(1215,'tl','home.faq.ordering.q4','Paano ako mag-order?');
INSERT INTO translations VALUES(1216,'tl','home.faq.ordering.a4',replace('Maaari kang mag-order sa pamamagitan ng:\n1, Makipag-ugnay sa aming koponan sa pagbebenta nang direkta sa iyong mga kinakailangan sa materyal, dami, at address ng paghahatid\n2 、 Humiling ng isang libreng quote at sample (kung kinakailangan)\n3 、 Kumpirmahin ang order at gumawa ng pagbabayad\n4 、 Inaayos namin ang produksyon at pagpapadala, at nagbibigay ng mga update sa pagsubaybay sa real-time','\n',char(10)));
