INSERT INTO translations VALUES(1272,'vi','0','Giấy phát hành');
INSERT INTO translations VALUES(1273,'vi','1','Độ dày màng');
INSERT INTO translations VALUES(1274,'vi','2','Bóng');
INSERT INTO translations VALUES(1275,'vi','3','Chúng tôi xuất khẩu sang Đông Nam Á, Châu Âu, Châu Mỹ, Trung Đông và các thị trường toàn cầu khác. Sản phẩm của chúng tôi được biết đến với độ bền, khả năng tùy chỉnh và giá xuất xưởng cạnh tranh.');
INSERT INTO translations VALUES(1276,'vi','4','Trao quyền cho các chuyên gia quảng cáo và doanh nghiệp sản xuất bảng hiệu trên toàn thế giới với các vật liệu chất lượng cao, đáng tin cậy để đạt được công việc sáng tạo xuất sắc với giá xuất xưởng cạnh tranh.');
INSERT INTO translations VALUES(1277,'vi','5','Trở thành một cái tên nổi tiếng trong lĩnh vực sản xuất vật liệu quảng cáo toàn cầu - được biết đến với sự đổi mới sản phẩm, ổn định chất lượng và mối quan hệ khách hàng bền chặt lâu dài.');
INSERT INTO translations VALUES(1278,'vi','6','Chất lượng đầu tiên. Trung thực và đáng tin cậy. Cải tiến liên tục. Lấy khách hàng làm trung tâm. Mỗi lô phải đáp ứng các tiêu chuẩn mà chúng tôi đặt ra cho chính mình - không chỉ là các tiêu chuẩn có thể chấp nhận được.');
INSERT INTO translations VALUES(1279,'vi','7','Phật Sơn, Quảng Đông, Trung Quốc');
INSERT INTO translations VALUES(1280,'vi','8','2009 · Năm thành lập');
INSERT INTO translations VALUES(1281,'vi','9','Công ty được thành lập');
INSERT INTO translations VALUES(1282,'vi','10','Công ty TNHH Vật liệu Quảng cáo Phật Sơn Jinyu chính thức được thành lập tại quận Nam Hải, Phật Sơn. Dòng sản phẩm ban đầu tập trung vào tấm xốp PVC và vinyl tự dính cho thị trường nội địa.');
INSERT INTO translations VALUES(1283,'vi','11','Tháng Mười 2022');
INSERT INTO translations VALUES(1284,'vi','12','Lô khách hàng quốc tế đầu tiên - Hội chợ Canton');
INSERT INTO translations VALUES(1285,'vi','13','Lần đầu tiên tham gia Hội chợ Canton. Thiết lập thành công mối quan hệ hợp tác với người mua nước ngoài từ Đông Nam Á, Trung Đông và Châu Âu.');
INSERT INTO translations VALUES(1286,'vi','14','Tháng Ba 2023');
INSERT INTO translations VALUES(1287,'vi','15','Đội ngũ R & D được thành lập');
INSERT INTO translations VALUES(1288,'vi','16','Thành lập một đội ngũ R & D chuyên nghiệp để thúc đẩy đổi mới sản phẩm, phát triển công thức tùy chỉnh và cung cấp khả năng hỗ trợ kỹ thuật cho khách hàng quốc tế.');
INSERT INTO translations VALUES(1289,'vi','17','Tháng Bảy 2023');
INSERT INTO translations VALUES(1290,'vi','18','Mở rộng công suất');
INSERT INTO translations VALUES(1291,'vi','19','Đầu tư mạnh vào dây chuyền sản xuất mới và thiết bị tiên tiến. Năng lực sản xuất đã được tăng lên đáng kể để đáp ứng khối lượng đơn đặt hàng quốc tế ngày càng tăng.');
INSERT INTO translations VALUES(1292,'vi','20','Năm 2024');
INSERT INTO translations VALUES(1293,'vi','21','Chứng nhận ISO 9001');
INSERT INTO translations VALUES(1294,'vi','22','Hoàn thành thành công chứng nhận hệ thống quản lý chất lượng ISO 9001:2015. Tài liệu chất lượng toàn diện và hệ thống cải tiến liên tục được chính thức thiết lập.');
INSERT INTO translations VALUES(1295,'vi','23','Thiết bị sản xuất');
INSERT INTO translations VALUES(1296,'vi','24','Mở rộng dây chuyền đùn tiên tiến, thiết bị cán, máy sơn và hệ thống rạch vào năm 2023');
INSERT INTO translations VALUES(1297,'vi','25','Phòng thí nghiệm R & D');
INSERT INTO translations VALUES(1298,'vi','26','Các phòng thí nghiệm thử nghiệm nội bộ và nhóm R & D cho các công thức tùy chỉnh, phát triển sản phẩm và xác nhận chất lượng');
INSERT INTO translations VALUES(1299,'vi','27','Kho xuất khẩu');
INSERT INTO translations VALUES(1300,'vi','28','Khu đóng gói xuất khẩu chuyên dụng với bao bì chống ẩm và chống va đập phù hợp với các lô hàng quốc tế');
INSERT INTO translations VALUES(1301,'vi','29','Quy trình kiểm soát chất lượng');
INSERT INTO translations VALUES(1302,'vi','30','Kiểm tra nguyên liệu thô → kiểm tra quy trình → kiểm tra thành phẩm → xác minh bao bì → kiểm tra trước khi giao hàng');
INSERT INTO translations VALUES(1303,'vi','31','Logistics xuất khẩu');
INSERT INTO translations VALUES(1304,'vi','32','FOB Quảng Châu / Phật Sơn. LCL và FCL được hỗ trợ. Làm việc với các công ty giao nhận hàng hóa lớn.');
INSERT INTO translations VALUES(1305,'vi','33','OEM / Đơn đặt hàng tùy chỉnh');
INSERT INTO translations VALUES(1306,'vi','34','Bao bì nhãn hiệu riêng, thông số kỹ thuật tùy chỉnh, kết hợp màu sắc và dây chuyền sản xuất độc quyền.');
INSERT INTO translations VALUES(1307,'vi','35','Vivian');
INSERT INTO translations VALUES(1308,'vi','36','Giám đốc bán hàng xuất khẩu');
INSERT INTO translations VALUES(1309,'vi','37','Bán hàng B2B quốc tế, quan hệ khách hàng và tài liệu xuất khẩu. Liên hệ trực tiếp cho tất cả các yêu cầu quốc tế.');
INSERT INTO translations VALUES(1310,'vi','38','Bộ phận R & D');
INSERT INTO translations VALUES(1311,'vi','39','Đội ngũ phát triển kỹ thuật');
INSERT INTO translations VALUES(1312,'vi','40','Đổi mới sản phẩm, công thức tùy chỉnh, kiểm soát chất lượng và tài liệu kỹ thuật tuân thủ quốc tế.');
