INSERT INTO translations VALUES(1314,'vi','42','Sản xuất & Kiểm soát chất lượng');
INSERT INTO translations VALUES(1315,'vi','43','Đội ngũ nhân viên sản xuất giàu kinh nghiệm vận hành cơ sở sản xuất mở rộng của chúng tôi theo quy trình chất lượng ISO 9001.');
