INSERT INTO translations VALUES(1776,'vi','home.about.desc','Công ty TNHH Vật liệu Quảng cáo Phật Sơn Jin Yu là nhà sản xuất tài liệu quảng cáo chuyên nghiệp tích hợp thiết kế, R & D, sản xuất và bán hàng. Tọa lạc tại thị trấn LiShui, quận Nam Hải, Phật Sơn - trung tâm của ngành công nghiệp vật liệu quảng cáo của Trung Quốc.');
