INSERT INTO translations VALUES(1828,'vi','home.faq.products.q1','Sản phẩm chính của bạn là gì?');
INSERT INTO translations VALUES(1829,'vi','home.faq.products.a1','Chúng tôi chuyên về Vinyl tự dính, Băng rôn PVC, Phim cắt Plotter, Tấm Acrylic, Tấm xốp PVC và Thiết bị trưng bày. Chúng tôi cũng cung cấp các thông số kỹ thuật tùy chỉnh theo yêu cầu của bạn.');
INSERT INTO translations VALUES(1830,'vi','home.faq.products.q2','Bạn có cung cấp kích thước và thông số kỹ thuật tùy chỉnh không?');
INSERT INTO translations VALUES(1831,'vi','home.faq.products.a2','Có, chúng tôi cung cấp kích thước, độ dày và thông số kỹ thuật tùy chỉnh. Vui lòng cung cấp yêu cầu chi tiết của bạn, và đội ngũ của chúng tôi sẽ đưa ra giải pháp phù hợp với nhu cầu của bạn.');
INSERT INTO translations VALUES(1832,'vi','home.faq.products.q3','Số lượng đặt hàng tối thiểu (MOQ) của bạn là bao nhiêu?');
INSERT INTO translations VALUES(1833,'vi','home.faq.products.a3','MOQ của chúng tôi thay đổi tùy theo loại sản phẩm. Nói chung, đó là 100 chiếc cho các sản phẩm tiêu chuẩn. Đối với đơn đặt hàng tùy chỉnh, vui lòng liên hệ trực tiếp với chúng tôi để biết các yêu cầu cụ thể.');
INSERT INTO translations VALUES(1834,'vi','home.faq.ordering.q1','Bạn chấp nhận những phương thức thanh toán nào?');
INSERT INTO translations VALUES(1835,'vi','home.faq.ordering.a1','Chúng tôi chấp nhận T/T (Chuyển khoản), PayPal và Western Union. Đối với khách hàng mới, chúng tôi có thể yêu cầu đặt cọc 30% với số dư được thanh toán trước khi giao hàng.');
INSERT INTO translations VALUES(1836,'vi','home.faq.ordering.q2','Mất bao lâu để xử lý đơn đặt hàng của tôi?');
INSERT INTO translations VALUES(1837,'vi','home.faq.ordering.a2','Thời gian sản xuất thay đổi tùy theo sản phẩm. Các sản phẩm tiêu chuẩn được giao trong vòng 3-7 ngày. Đơn đặt hàng tùy chỉnh có thể mất 10-15 ngày. Chúng tôi sẽ cung cấp ngày giao hàng ước tính khi xác nhận đơn đặt hàng.');
INSERT INTO translations VALUES(1838,'vi','home.faq.ordering.q3','Tôi có thể yêu cầu mẫu trước khi đặt hàng số lượng lớn không?');
INSERT INTO translations VALUES(1839,'vi','home.faq.ordering.a3','Có, chúng tôi cung cấp mẫu miễn phí cho các sản phẩm tiêu chuẩn. Khách hàng chỉ cần thanh toán chi phí vận chuyển. Đối với mẫu tùy chỉnh, vui lòng liên hệ với chúng tôi để biết giá.');
INSERT INTO translations VALUES(1840,'vi','home.faq.shipping.q1','Bạn có vận chuyển quốc tế không?');
INSERT INTO translations VALUES(1841,'vi','home.faq.shipping.a1','Có, chúng tôi giao hàng đến hơn 50 quốc gia trên toàn thế giới. Chúng tôi làm việc với các hãng vận chuyển lớn như DHL, FedEx, UPS và vận chuyển đường biển cho các đơn hàng lớn hơn.');
INSERT INTO translations VALUES(1842,'vi','home.faq.shipping.q2','Chi phí vận chuyển là bao nhiêu?');
INSERT INTO translations VALUES(1843,'vi','home.faq.shipping.a2','Chi phí vận chuyển phụ thuộc vào điểm đến, trọng lượng và phương thức vận chuyển. Chúng tôi cung cấp giá cạnh tranh và sẽ báo giá chính xác cho bạn khi bạn đặt hàng.');
INSERT INTO translations VALUES(1844,'vi','home.faq.shipping.q3','Giao hàng mất bao lâu?');
INSERT INTO translations VALUES(1845,'vi','home.faq.shipping.a3','Vận chuyển nhanh (DHL/FedEx/UPS) mất 5-7 ngày làm việc. Vận chuyển đường biển mất 25-35 ngày tùy thuộc vào quốc gia và cảng đến.');
INSERT INTO translations VALUES(1846,'vi','home.faq.quality.q1','Sản phẩm của bạn có chứng nhận không?');
INSERT INTO translations VALUES(1847,'vi','home.faq.quality.a1','Có, chúng tôi đã đạt chứng nhận ISO 9001:2015. Sản phẩm của chúng tôi đáp ứng các tiêu chuẩn chất lượng quốc tế và được xuất khẩu sang châu Âu, châu Mỹ, Đông Nam Á và Trung Đông.');
INSERT INTO translations VALUES(1848,'vi','home.faq.quality.q2','Bạn có cung cấp bảo hành chất lượng không?');
INSERT INTO translations VALUES(1849,'vi','home.faq.quality.a2','Hoàn toàn có! Chúng tôi cung cấp bảo hành chất lượng 100%. Nếu bạn nhận được sản phẩm lỗi, chúng tôi sẽ thay thế miễn phí hoặc hoàn tiền đầy đủ.');
INSERT INTO translations VALUES(1850,'vi','home.faq.quality.q3','Bạn có thể cung cấp báo cáo thử nghiệm hoặc mẫu không?');
INSERT INTO translations VALUES(1851,'vi','home.faq.quality.a3','Có, chúng tôi có thể cung cấp báo cáo thử nghiệm, chứng chỉ và mẫu theo yêu cầu. Đội ngũ kiểm soát chất lượng của chúng tôi tiến hành kiểm tra kỹ lưỡng trước khi giao hàng.');
