INSERT INTO translations VALUES(1858,'vi','faq.q1_5','Bạn cung cấp những tài liệu quảng cáo nào?');
INSERT INTO translations VALUES(1859,'vi','faq.a1_5',replace('Chúng tôi cung cấp đầy đủ các tài liệu quảng cáo hiệu suất cao phù hợp với thị trường Đông Nam Á, bao gồm:\nVán Sintra (ván xốp PVC)\nVinyl tự dính (có thể in, màu, phản chiếu)\nMàng pha lê chống trầy xước cấp quang học\nBiểu ngữ PVC flex\nTấm acrylic\nVật liệu chữ kênh LED\nTấm phản quang và các màng chức năng khác','\n',char(10)));
