INSERT INTO translations VALUES(1861,'vi','home.faq.products.a5',replace('Chúng tôi cung cấp đầy đủ các tài liệu quảng cáo hiệu suất cao phù hợp với thị trường Đông Nam Á, bao gồm:\nVán Sintra (ván xốp PVC)\nVinyl tự dính (có thể in, màu, phản chiếu)\nMàng pha lê chống trầy xước cấp quang học\nBiểu ngữ PVC flex\nTấm acrylic\nVật liệu chữ kênh LED\nTấm phản quang và các màng chức năng khác','\n',char(10)));
INSERT INTO translations VALUES(1862,'vi','faq.q2_4','Làm thế nào để đặt hàng?');
INSERT INTO translations VALUES(1863,'vi','faq.a2_4',replace('Bạn có thể đặt hàng qua:\n1 、 Liên hệ trực tiếp với nhóm bán hàng của chúng tôi với yêu cầu vật liệu, số lượng và địa chỉ giao hàng của bạn\n2 、 Yêu cầu báo giá và mẫu miễn phí (nếu cần)\n3 、 Xác nhận đơn đặt hàng và thanh toán\n4 、 Chúng tôi sắp xếp sản xuất và vận chuyển, đồng thời cung cấp các bản cập nhật theo dõi theo thời gian thực','\n',char(10)));
INSERT INTO translations VALUES(1864,'vi','home.faq.ordering.q4','Làm thế nào để đặt hàng?');
INSERT INTO translations VALUES(1865,'vi','home.faq.ordering.a4',replace('Bạn có thể đặt hàng qua:\n1 、 Liên hệ trực tiếp với nhóm bán hàng của chúng tôi với yêu cầu vật liệu, số lượng và địa chỉ giao hàng của bạn\n2 、 Yêu cầu báo giá và mẫu miễn phí (nếu cần)\n3 、 Xác nhận đơn đặt hàng và thanh toán\n4 、 Chúng tôi sắp xếp sản xuất và vận chuyển, đồng thời cung cấp các bản cập nhật theo dõi theo thời gian thực','\n',char(10)));
INSERT INTO translations VALUES(1866,'vi','faq.q3_4','Bạn cung cấp những tùy chọn vận chuyển nào đến Đông Nam Á?');
INSERT INTO translations VALUES(1867,'vi','faq.a3_4',replace('Chúng tôi cung cấp nhiều giải pháp vận chuyển để giao hàng nhanh chóng, đáng tin cậy đến Việt Nam, Philippines và các nước Đông Nam Á khác:\nVận chuyển nhanh (DHL, FedEx, UPS): 3-7 ngày đối với đơn đặt hàng / mẫu nhỏ\nVận tải hàng không: 7-15 ngày đối với đơn hàng cỡ trung bình\nVận tải đường biển: 20-35 ngày đối với các đơn đặt hàng số lượng lớn (tiết kiệm chi phí nhất)','\n',char(10)));
