INSERT INTO translations VALUES(1869,'vi','home.faq.shipping.a4',replace('Chúng tôi cung cấp nhiều giải pháp vận chuyển để giao hàng nhanh chóng, đáng tin cậy đến Việt Nam, Philippines và các nước Đông Nam Á khác:\nVận chuyển nhanh (DHL, FedEx, UPS): 3-7 ngày đối với đơn đặt hàng / mẫu nhỏ\nVận tải hàng không: 7-15 ngày đối với đơn hàng cỡ trung bình\nVận tải đường biển: 20-35 ngày đối với các đơn đặt hàng số lượng lớn (tiết kiệm chi phí nhất)','\n',char(10)));
