INSERT INTO translations VALUES(2521,'en','home.faq.products.q1','What are your main products?');
INSERT INTO translations VALUES(2522,'en','home.faq.products.a1','We specialize in Self Adhesive Vinyl, PVC Flex Banner, Cutting Plotter Film, Acrylic Sheet, PVC Foam Board, and Display Equipment. We also offer custom specifications according to your requirements.');
INSERT INTO translations VALUES(2523,'en','home.faq.products.q2','Do you offer custom sizes and specifications?');
INSERT INTO translations VALUES(2524,'en','home.faq.products.a2','Yes, we offer custom sizes, thickness, and specifications. Please provide your detailed requirements, and our team will provide a solution tailored to your needs.');
INSERT INTO translations VALUES(2525,'en','home.faq.products.q3','What is your minimum order quantity (MOQ)?');
INSERT INTO translations VALUES(2526,'en','home.faq.products.a3','Our MOQ varies by product type. Generally, it''s 100 pieces for standard products. For custom orders, please contact us directly for specific requirements.');
INSERT INTO translations VALUES(2527,'en','home.faq.ordering.q1','What payment methods do you accept?');
INSERT INTO translations VALUES(2528,'en','home.faq.ordering.a1','We accept T/T (Wire Transfer), PayPal, and Western Union. For new customers, we may require a 30% deposit with the balance paid before shipment.');
INSERT INTO translations VALUES(2529,'en','home.faq.ordering.q2','How long does it take to process my order?');
INSERT INTO translations VALUES(2530,'en','home.faq.ordering.a2','Production time varies by product. Standard products ship within 3-7 days. Custom orders may take 10-15 days. We''ll provide an estimated delivery date upon order confirmation.');
INSERT INTO translations VALUES(2531,'en','home.faq.ordering.q3','Can I request samples before placing a bulk order?');
INSERT INTO translations VALUES(2532,'en','home.faq.ordering.a3','Yes, we offer free samples for standard products. Customers only need to cover the shipping cost. For custom samples, please contact us for pricing.');
INSERT INTO translations VALUES(2533,'en','home.faq.shipping.q1','Do you ship internationally?');
INSERT INTO translations VALUES(2534,'en','home.faq.shipping.a1','Yes, we ship to over 50 countries worldwide. We work with major shipping carriers like DHL, FedEx, UPS, and sea freight for larger orders.');
INSERT INTO translations VALUES(2535,'en','home.faq.shipping.q2','What are the shipping costs?');
INSERT INTO translations VALUES(2536,'en','home.faq.shipping.a2','Shipping costs depend on destination, weight, and shipping method. We provide competitive rates and will quote you the exact shipping cost when you place your order.');
INSERT INTO translations VALUES(2537,'en','home.faq.shipping.q3','How long does delivery take?');
INSERT INTO translations VALUES(2538,'en','home.faq.shipping.a3','Express shipping (DHL/FedEx/UPS) takes 5-7 business days. Sea freight takes 25-35 days depending on the destination country and port.');
INSERT INTO translations VALUES(2539,'en','home.faq.quality.q1','Are your products certified?');
INSERT INTO translations VALUES(2540,'en','home.faq.quality.a1','Yes, we are ISO 9001:2015 certified. Our products meet international quality standards and are exported to Europe, Americas, Southeast Asia, and Middle East markets.');
INSERT INTO translations VALUES(2541,'en','home.faq.quality.q2','Do you offer quality guarantees?');
INSERT INTO translations VALUES(2542,'en','home.faq.quality.a2','Absolutely! We offer a 100% quality guarantee. If you receive defective products, we will replace them free of charge or provide a full refund.');
INSERT INTO translations VALUES(2543,'en','home.faq.quality.q3','Can you provide test reports or samples?');
INSERT INTO translations VALUES(2544,'en','home.faq.quality.a3','Yes, we can provide test reports, certificates, and samples upon request. Our quality control team conducts thorough inspections before shipment.');
