INSERT INTO translations VALUES(2552,'en','faq.a1_5',replace('We provide a full range of high-performance advertising materials tailored for Southeast Asian markets, including:\nSintra board (PVC foam board)\nSelf-adhesive vinyl (printable, colored, reflective)\nOptical grade anti-scratch crystal film\nPVC flex banner\nAcrylic sheet\nLED channel letter materials\nReflective sheeting and other functional films','\n',char(10)));
