INSERT INTO team_members VALUES(10,'vivian',1,0,'Vivian','薇薇安','Vivian','Si Vivian','Export Sales Manager','出口销售经理','Giám đốc kinh doanh xuất khẩu','Sales Manager ng Export','International B2B sales, client relations and export documentation. Direct contact for all international enquiries.','国际B2B销售、客户关系及出口文件。所有国际咨询均可直接联系。','Bán hàng B2B quốc tế, quan hệ khách hàng và tài liệu xuất khẩu. Liên hệ trực tiếp cho tất cả các yêu cầu quốc tế.','Internasyonal na benta ng B2B, relasyon sa kliyente at dokumentasyon ng pag-export. Direktang pakikipag-ugnay para sa lahat ng mga internasyonal na katanungan.','/about-uploads/1776012229059-x889gh.jpg','vivian@materials-ad.com','#2563eb','V','2026-05-04 09:21:26');
INSERT INTO team_members VALUES(11,'r&d-department',1,1,'R&D Department','研发部','Bộ phận R & D','Kagawaran ng R&D','Technical Development Team','技术开发团队','Đội ngũ phát triển kỹ thuật','Teknikal na Koponan sa Pag-unlad','Product innovation, custom formulation, quality control, and technical documentation for international compliance.','产品创新、定制配方、质量控制以及国际合规技术文档。','Đổi mới sản phẩm, công thức tùy chỉnh, kiểm soát chất lượng và tài liệu kỹ thuật để tuân thủ quốc tế.','Pagbabago ng produkto, pasadyang pagbabalangkas, kontrol sa kalidad, at teknikal na dokumentasyon para sa internasyonal na pagsunod.','','','#E8751A','R','2026-05-04 09:21:26');
INSERT INTO team_members VALUES(12,'production-team',1,2,'Production Team','制作团队','Đội ngũ sản xuất','Koponan ng Produksyon','Manufacturing & QC','制造与质量控制','Sản xuất & QC','Pagmamanupaktura at QC','Experienced production workforce operating our expanded manufacturing facility with ISO 9001 quality procedures.','经验丰富的生产团队运营着我们扩展后的制造设施，采用ISO 9001质量标准。','Lực lượng lao động sản xuất giàu kinh nghiệm vận hành cơ sở sản xuất mở rộng của chúng tôi với quy trình chất lượng ISO 9001.','Nakaranas ng mga manggagawa sa produksyon na nagpapatakbo ng aming pinalawak na pasilidad sa pagmamanupaktura na may mga pamamaraan sa kalidad ng ISO 9001.','','','#3a7ab8','P','2026-05-04 09:21:26');
INSERT INTO team_members VALUES(13,'hugo',1,3,'HUGO','','','','Founder & General Manager','','','','With decades of experience in the advertising materials industry, he leads the company’s overall strategy, product development and quality management. He focuses on stable product performance and global market expansion, dedicated to offering cost-effective and reliable advertising material solutions for Southeast Asian partners.','','','','/about-uploads/1776683722271-yygqqo.jpg','','#eb7324','?','2026-05-04 09:21:26');
